#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long val;
    int lson,rson;
}a[2000010];
int dis[2000010],fa1[2000010],fa[2000010];
long long find(long long x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
long long merge(long long x,long long y)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    if(a[x].val<a[y].val||(a[x].val==a[y].val&&x>y))
    {
        swap(x,y);
    }
    a[x].rson=merge(a[x].rson,y);
    fa1[a[x].rson]=x;
    if(dis[a[x].lson]<dis[a[x].rson])
    {
        swap(a[x].lson,a[x].rson);
    }
    fa[a[x].lson]=fa[a[x].rson]=x;
    dis[x]=dis[a[x].rson]+1;
    return x;
}
long long remove(long long x)
{
    long long tmp=find(x);
    fa[a[x].lson]=a[x].lson;
    fa[a[x].rson]=a[x].rson;
    long long now=merge(a[x].lson,a[x].rson);
    fa[x]=now;
    fa1[now]=fa1[x];
    long long f=fa1[x];
    if(tmp!=x)
    {
        fa[now]=tmp;
        if(a[f].lson==x)
        {
            a[f].lson=now;
        }
        else
        {
            a[f].rson=now;
        }
        while(f)
        {
            if(dis[now]+1>=dis[f])
            {
                break;
            }
            dis[f]=dis[now]+1;
            if(dis[a[f].lson]<dis[a[f].rson])
            {
                swap(a[f].lson,a[f].rson);
            }
            f=fa1[f];
        }
    }
    a[x].lson=a[x].rson=a[x].val=dis[x]=0;
    return find(now);
}
int main()
{
    long long t,w,k;
    scanf("%lld%lld%lld",&t,&w,&k);
    while(t--)
    {
        long long n,m;
        scanf("%lld%lld",&n,&m);
        memset(a,0,sizeof(a));
        memset(dis,0,sizeof(dis));
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i].val);
            fa[i]=i;
        }
        while(m--)
        {
            long long op,x,y;
            scanf("%lld%lld",&op,&x);
            if(op==2)
            {
                long long tmp=remove(x);
                fa[tmp]=fa[x]=merge(x,tmp);
            }
            else if(op==3)
            {
                scanf("%lld",&y);
                x=find(x);
                fa[a[x].lson]=a[x].lson;
                fa[a[x].rson]=a[x].rson;
                long long tmp=merge(a[x].lson,a[x].rson);
                a[x].lson=a[x].rson=0;
                dis[x]=0;
                a[x].val=max(0ll,a[x].val-y);
                fa[x]=fa[tmp]=merge(tmp,x);
            }
            else
            {
                scanf("%lld",&y);
                x=find(x),y=find(y);
                if(x!=y)
                {
                    merge(x,y);
                }
            }
        }
        long long sum=0,max1=0;
        for(long long i=1;i<=n;i++)
        {
            long long x=find(i);
            if(i!=x)
            {
                continue;
            }
            max1=max(max1,1ll*a[x].val);
            sum+=a[x].val;
        }
        if(w==2)
        {
            sum-=max1;
        }
        if(w==3)
        {
            sum+=max1;
        }
        if(sum==0)
        {
            printf("Gensokyo 0\n");
        }
        else if(sum<=k)
        {
            printf("Heaven %lld\n",sum);
        }
        else
        {
            printf("Hell %lld\n",sum);
        }
    }
    return 0;
}
